entries.body:
Let $(M,g)$ be a complete Riemannian $n$-manifold admitting a nontrivial $f$
  with $\operatorname{Hess}f=\lambda g$. Then $(M,g)$ is isometric to a complete
  warped product metric of one of the forms:
  \begin{enumerate}
  \item[(1)] $M=\mathbb R\times N$, $g=dr^2+\rho^2(r)g_N$;
  \item[(2)] $M=\mathbb R^n$, $g=dr^2+\rho^2(r)ds_{n-1}^2$, $r>0$;
  \item[(3)] $M=S^n$, $g=dr^2+\rho^2(r)ds_{n-1}^2$, $r\in[a,b]$.
  \end{enumerate}

Let $(M,g)$ be complete of dimension $n$ with a nontrivial $f$,
  $\operatorname{Hess}f=(\alpha f+\beta)g$, $\alpha,\beta\in\mathbb R$. Then
  $(M,g)$ is one of:
  \begin{enumerate}
  \item[(a)] $(I\times S^{n-1},\,dr^2+\mathrm{sn}_k^2(r)ds_{n-1}^2)$: a constant
  curvature space form;
  \item[(b)] $(\mathbb R\times N,\,dr^2+g_N)$: a product metric;
  \item[(c)] $\big(\mathbb R\times N,\,dr^2+(A\exp(\sqrt\alpha r)+B\exp(-\sqrt\alpha r))^2h\big)$,
  $A,B\ge0$.
  \end{enumerate}

Surfaces of revolution $dr^2+\rho^2(r)ds^2_{n-1}$ with $\rho:[0,\infty)\to
  [0,\infty)$, $\dot\rho(t)<1$, $\ddot\rho(t)<0$ for $t>0$, contain no lines;
  such manifolds look like paraboloids.

The functions $b_t$, $t\ge0$, satisfy:
  \begin{enumerate}
    \item[(1)] for fixed $x$, $t\mapsto b_t(x)$ is decreasing and bounded in
      absolute value by $|xc(0)|$;
    \item[(2)] $|b_t(x)-b_t(y)|\le|xy|$;
    \item[(3)] $\Delta b_t(x)\le\dfrac{n-1}{b_t(x)+t}$ everywhere.
  \end{enumerate}

With $c,p,\tilde c$ as in \cref{def:pet-ch7-horosphere-asymptote}, the
  Busemann functions satisfy
  \begin{enumerate}
    \item[(1)] $b_c(x)\le b_c(p)+b_{\tilde c}(x)$ for all $x\in M$;
    \item[(2)] $b_c(\tilde c(t))=b_c(p)+b_{\tilde c}(\tilde c(t))=b_c(p)-t$ for
      all $t\ge0$.
  \end{enumerate}

Suppose $(M,g)$ is compact with $\Ric\ge0$. Then:
  \begin{enumerate}
    \item[(1)] the universal cover $(\tilde M,\tilde g)$ splits isometrically
      as $N\times\mathbb{R}^k$, with $N$ compact and containing no lines;
    \item[(2)] $\Iso(\tilde M)=\Iso(N)\times\Iso(\mathbb{R}^k)$;
    \item[(3)] there is a finite normal subgroup $G\subset\pi_1(M)$ with
      $\pi_1(M)/G\cong\pi_1(M)\cap\Iso(\mathbb{R}^k)$, and a finite-index subgroup
      $\mathbb{Z}^k\subset\pi_1(M)\cap\Iso(\mathbb{R}^k)$.
  \end{enumerate}

If $X$ and $\theta$ are related by $\theta(v)=g(v,X)$, then
  \begin{enumerate}
    \item $v\mapsto\nabla_vX$ is symmetric if and only if $d\theta=0$, and
    \item $\operatorname{div}X=-\delta\theta$.
  \end{enumerate}

Let $(M,g)$ be a compact Riemannian $n$-manifold with nonnegative curvature
  operator. Then one of:
  \begin{enumerate}
    \item[(a)] $(M,g)$ is reducible or locally symmetric;
    \item[(b)] $\mathrm{Hol}^0(M,g)=\mathrm{SO}(n)$ and the universal cover is a
      homology sphere;
    \item[(c)] $\mathrm{Hol}^0(M,g)=\mathrm U(n/2)$ and the universal cover is a
      homology $\mathbb{CP}^{n/2}$.
  \end{enumerate}

Let $(M,g)$ be a compact Riemannian $n$-manifold with nonnegative complex
  sectional curvature. Then one of:
  \begin{enumerate}
    \item[(a)] $(M,g)$ is reducible or locally symmetric;
    \item[(b)] $M$ is diffeomorphic to a space of constant positive curvature;
    \item[(c)] the universal cover of $M$ is biholomorphic to $\mathbb{CP}^{n/2}$.
  \end{enumerate}

On a harmonic coordinate system $x:U\to\mathbb{R}^n$ for $(M,g)$,
  \begin{equation}
    \Delta u=\frac1{\sqrt{\det g_{ij}}}\partial_i\big(\sqrt{\det g_{ij}}\,g^{ij}\partial_ju\big)=g^{ij}\partial_i\partial_ju,
  \end{equation}
  \begin{equation}
    \tfrac12\Delta g_{ij}+Q(g,\partial g)=-\Ric_{ij}=-\Ric(\partial_i,\partial_j),
  \end{equation}
  where $Q$ is a universal rational expression, polynomial in $g$ and
  quadratic in $\partial g$ in the numerator, with denominator a power of
  $\sqrt{\det g_{ij}}$.

If $(M,g)$ is closed with $\sec\ge1$ and $\mathrm{diam}\ge\pi/2$, then one of
  the following holds:
  \begin{enumerate}
    \item $M$ is homeomorphic to a sphere;
    \item $M$ is isometric to a finite quotient $S^n(1)/\Gamma$ with $\Gamma$
      acting reducibly (an invariant subspace exists);
    \item $M$ is isometric to $\mathbb{CP}^m$, $\mathbb{HP}^m$, or
      $\mathbb{CP}^m/\mathbb{Z}_2$ for $m$ odd;
    \item $M$ is isometric to $\mathbb{OP}^2$.
  \end{enumerate}

There is $C(n)$ such that any complete $M$ with $\sec\ge0$ satisfies:
  \begin{enumerate}
    \item $\pi_1(M)$ can be generated by $\le C(n)$ elements;
    \item for every field $\mathbb{F}$,
      $\sum_{i=0}^n b_i(M,\mathbb{F})=\sum_{i=0}^n\dim H_i(M,\mathbb{F})\le C(n)$.
  \end{enumerate}
